#ifndef PredictInterface_hpp
#define PredictInterface_hpp

#include <stdio.h>
#include <vector>
#include <string>
#include <deque>
#include <set>
#include <cmath>
#import <XPBucket/DDLogDefine.h>
#import "XPLogTagMacro.h"
using namespace std;

struct ble_rssi {
    short rssi = 0;
    string name = "";
};

struct decision_rssi {
    vector<short> rssi;
    string name = "";
};

struct on_time_distance {
    float distance = 0;
    short rssi = 0;
    bool is_communicate = false;
    string name = "";
};

struct ble_config_info {
    short txPower = 0;
    float a = 0;
    float b = 0;
    float c = 0;
    string name = "";
    bool is_communicate = false;
};

struct ble_cover_map {
    string name = "";
    float moreScale = 1;
    float lessScale = 0;
    bool isWeightPriority = true;
};

struct ble_is_map_scale {
    bool isWeightPriority = true;
    float scale = 0;
    string name = "";
};

struct bussiness_distance {
    float unlockDistance = 4;
    float lockDistance = 7;
    float enableDistance = 6;
};

namespace BLE_SDK {

class PredictInterface {

public:
    void init();
    virtual void reset();
    void PredictLog(NSString *log);
    NSString* printFloatVectorInput(deque<vector<float>> &input);
    NSString* printFloatVector(vector<float> &input);

    const short DISCONNECT_RSSI = -120;

};

}

#endif /* PredictInterface_hpp */

