//
//  XPPollingPredictInterfaceOpt.m
//  XPCarControlCore
//
//  Created by huzy2 on 2023/3/20.
//

#include "PLXPPollingPredictInterfaceOpt.h"

void PLXPPollingPredictInterfaceOpt::reset() {
    PLPredictInterface::reset();
    fullRSSIWindow.clear();
}

NSString* printInput(deque<vector<ble_rssi>> &input) {
    NSString *string = @"input array:";
    for (int i = 0; i<input.size(); i++) {
        vector<ble_rssi> &sub = input[i];
        string = [string stringByAppendingString:@"\r\n["];
        for (int j=0; j<sub.size(); j++) {
            string = [string stringByAppendingString:[@(sub[j].rssi) stringValue]];
            string = [string stringByAppendingString:@" "];
        }
        string = [string stringByAppendingString:@"]"];
    }
    return string;
}

NSString* printVector(vector<ble_rssi> &input) {
    NSString *string = @"当前窗口数据:";
    for (int j=0; j<input.size(); j++) {
        string = [string stringByAppendingString:[NSString stringWithUTF8String:input[j].name.c_str()]];
        string = [string stringByAppendingString:@","];
        string = [string stringByAppendingString:[@(input[j].rssi) stringValue]];
        string = [string stringByAppendingString:@" "];
    }
    string = [string stringByAppendingString:@"]"];
    return string;
}

NSString* printBleConfigInfos(vector<ble_config_info> &bleConfigInfos) {
    NSString *string = @"bleConfigInfos:";
    for (int i = 0; i<bleConfigInfos.size(); i++) {
        string = [string stringByAppendingString:@"\r\n["];
        ble_config_info &bleConfigInfo = bleConfigInfos[i];
        string = [string stringByAppendingString:[NSString stringWithFormat:@"name=%@",[NSString stringWithUTF8String:bleConfigInfo.name.c_str()]]];
        string = [string stringByAppendingString:[NSString stringWithFormat:@",txPower=%.2hd",bleConfigInfo.txPower]];
        string = [string stringByAppendingString:[NSString stringWithFormat:@",a=%.2f",bleConfigInfo.a]];
        string = [string stringByAppendingString:[NSString stringWithFormat:@",b=%.2f",bleConfigInfo.b]];
        string = [string stringByAppendingString:[NSString stringWithFormat:@",c=%.2f",bleConfigInfo.c]];
        string = [string stringByAppendingString:@" "];
        string = [string stringByAppendingString:@"]"];
    }
    return string;
}

void PLXPPollingPredictInterfaceOpt::setBleConfigs(vector<ble_config_info> &bleConfigs) {
    ble_configs = bleConfigs;
    DLogTagInfo(kBLEKeyPredictTag, printBleConfigInfos(bleConfigs));

}

bool compareFunction(ble_rssi &i,ble_rssi &j) {
    return i.rssi < j.rssi;
}

int getSum(int size) {
    if (size == 0) {
        return 0;
    }
    int sum = 0;
    for(int i=1;i<= size;i++){
        sum += i;
    }
    return sum;
}

float getLineWeight(int position,int size) {
    int sum = getSum(size);
    if (sum == 0) {
        return 0;
    } else {
        return (float)position/sum;
    }
}


void PLXPPollingPredictInterfaceOpt::filterSourceRssi() {
    auto rssiWindow = fullRSSIWindow;
    for (int i = 0; i<FREQUENCY_LENGTH; i++) {
        fullRSSIWindow.pop_front();
    }
    for (int i=0; i<ble_configs.size(); i++) {
        string name = "";
        vector<ble_rssi> v;
        for(int j=0; j<rssiWindow.size(); j++) {
            if (name.length() == 0) {
                name = rssiWindow[j][i].name;
            }
            if (rssiWindow[j][i].rssi != DISCONNECT_RSSI) {
                v.push_back(rssiWindow[j][i]);
            }
        }
        if (v.size() > rssiWindow.size() * MORE_DECISION_VAILD_RATE) {
            float sum = 0;
            int count = (int)v.size();
            for (int k=0; k<count; k++) {
                sum += v[k].rssi * getLineWeight(k+1,count);
            }
            short finalAverage = (int)(sum - 0.5);
            ble_rssi avgRssi;
            avgRssi.rssi = finalAverage;
            avgRssi.name = name;
            fullDecisionRssi.push_back(avgRssi);
        } else {
            v.clear();
            ble_rssi avgRssi;
            avgRssi.rssi = DISCONNECT_RSSI;
            avgRssi.name = name;
            fullDecisionRssi.push_back(avgRssi);
        }
    }
}


void PLXPPollingPredictInterfaceOpt::preprocess(vector<ble_rssi> &rssi, vector<vector<float>> &output) {
    output.clear();
    if (ble_configs.size() < 1) {
#ifdef XPPollingSDK_Test_Mode
        printf("%s", [@"标定参数为空，return\n" cStringUsingEncoding:NSUTF8StringEncoding]);
#endif  //XPPollingSDK_Test_Mode
        PredictLog([NSString stringWithFormat:@"标定参数为空，return"]);
        return;
    }
    for (int i=0; i<rssi.size(); i++) {
        ble_rssi &pointRssi = rssi[i];
        if(pointRssi.rssi == 0){
            pointRssi.rssi = DISCONNECT_RSSI;
        }
    }

    fullRSSIWindow.push_back(rssi);
    if(fullRSSIWindow.size() < DECISION_LENGTH){
        return;
    }

    //读取资料，并检查各位置数值
    vector<float> fullRSSI;
    for(int i=0; i<fullRSSIWindow.size(); i++){
        vector<ble_rssi> singleRssi = fullRSSIWindow[i];
        for (int j = 0; j < singleRssi.size(); j++) {
            fullRSSI.push_back(singleRssi[j].rssi);
        }
    }

    //滤波
    filterSourceRssi();
    for (int i=0;i<ble_configs.size();i++) {
        ble_config_info &bleConfig = ble_configs[i];
        fullRSSI.push_back(bleConfig.txPower);
    }
    output.push_back(fullRSSI);
}

float PLXPPollingPredictInterfaceOpt::calculateDistance(float measuredPower, float rssi, float a, float b, float c) {
    if (rssi == 0) {
        return -1.0; // if we cannot determine distance, return -1.
    }
    float ratio = rssi*1.0/measuredPower;
    if (ratio < 1.0) {
        return pow(ratio,10);
    }
    else {
        float distance =  (a)*pow(ratio,b) + c;
        return distance;
    }
}

void PLXPPollingPredictInterfaceOpt::inference(vector<on_time_distance> &output) {
    output.clear();
    PredictLog([NSString stringWithFormat:@"决策rssi:%@",printVector(fullDecisionRssi)]);

    for (int i=0;i<fullDecisionRssi.size();i++) {
        ble_rssi &decisionRssi = fullDecisionRssi[i];
        if (decisionRssi.rssi == DISCONNECT_RSSI) {
            on_time_distance finalDistance;
            finalDistance.distance = INVAILD_DISTANCE;
            finalDistance.name = decisionRssi.name;
            finalDistance.is_communicate = false;
            finalDistance.rssi = decisionRssi.rssi;
            output.push_back(finalDistance);
            continue;
        } else {
            ble_config_info *bleConfig = findMatchedBleConfig(decisionRssi.name);
            if (bleConfig != NULL) {
                float finalDistance = calculateDistance(bleConfig->txPower, decisionRssi.rssi, bleConfig->a, bleConfig->b, bleConfig->c);
                PredictLog([NSString stringWithFormat:@"%@:最终距离:%f", [NSString stringWithUTF8String:decisionRssi.name.c_str()], finalDistance]);
                on_time_distance distance;
                distance.distance = finalDistance;
                distance.name = bleConfig->name;
                distance.is_communicate = bleConfig->is_communicate;
                distance.rssi = decisionRssi.rssi;
                output.push_back(distance);
            } else {
                on_time_distance finalDistance;
                finalDistance.distance = INVAILD_DISTANCE;
                finalDistance.name = decisionRssi.name;
                finalDistance.is_communicate = false;
                finalDistance.rssi = decisionRssi.rssi;
                output.push_back(finalDistance);
                continue;
            }
        }
    }
    fullDecisionRssi.clear();
}

ble_config_info * PLXPPollingPredictInterfaceOpt::findMatchedBleConfig(string &name) {
